# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import NoBrokersAvailable, TopicAlreadyExistsError, UnknownTopicOrPartitionError

def create_topics(admin_client, topics_to_create):
    new_topics = []
    for topic_name, config in topics_to_create.items():
        try:
            num_partitions = int(config.get('partitions', 1))
            replication_factor = int(config.get('replication_factor', 1))
            topic_configs = {k: v for k, v in config.items() if k not in ['partitions', 'replication_factor']}
            new_topics.append(NewTopic(
                name=topic_name,
                num_partitions=num_partitions,
                replication_factor=replication_factor,
                topic_configs=topic_configs
            ))
            print(f"Prepared to create topic '{topic_name}' with {num_partitions} partitions, {replication_factor} replication factor, and configs: {topic_configs}")
        except ValueError as e:
            print(f"Error parsing configuration for topic '{topic_name}': {e}. Skipping topic.")
            continue

    if not new_topics:
        print("No valid topics prepared for creation.")
        return

    try:
        admin_client.create_topics(new_topics, validate_only=False)
        print("Topics created successfully.")
    except TopicAlreadyExistsError:
        print("Some topics already exist. Skipping creation for those.")
    except Exception as e:
        print(f"Error creating topics: {e}")

def describe_topics(admin_client, topic_names):
    if not topic_names:
        print("No topic names provided for description.")
        return

    try:
        topic_metadata = admin_client.describe_topics(topic_names)
        for topic in topic_metadata:
            print(f"\n--- Topic: {topic['topic']} ---")
            print(f"  Partitions: {len(topic['partitions'])}")
            print(f"  Is Internal: {topic['is_internal']}")
            for p in topic['partitions']:
                replicas = ','.join(str(r['id']) for r in p['replicas'])
                isr = ','.join(str(r['id']) for r in p['isr'])
                print(f"    Partition {p['id']}: Leader={p['leader']}, Replicas=[{replicas}], ISR=[{isr}]")
    except UnknownTopicOrPartitionError:
        print(f"One or more topics not found: {', '.join(topic_names)}")
    except Exception as e:
        print(f"Error describing topics: {e}")

def alter_topic_configs(admin_client, topic_name, configs_to_alter):
    if not configs_to_alter:
        print("No configurations provided for alteration.")
        return

    try:
        resource = ConfigResource(ConfigResourceType.TOPIC, topic_name, configs=configs_to_alter)
        admin_client.alter_configs([resource])
        print(f"Successfully altered configurations for topic '{topic_name}'.")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' not found.")
    except Exception as e:
        print(f"Error altering configurations for topic '{topic_name}': {e}")

def delete_topics(admin_client, topic_names):
    if not topic_names:
        print("No topic names provided for deletion.")
        return

    try:
        admin_client.delete_topics(topic_names)
        print(f"Topics '{', '.join(topic_names)}' deletion initiated.")
    except UnknownTopicOrPartitionError:
        print(f"One or more topics not found: {', '.join(topic_names)}. Deletion initiated for existing ones.")
    except Exception as e:
        print(f"Error deleting topics: {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("\n--- Available Topics ---")
        for topic_name in sorted(topics):
            print(f"  - {topic_name}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Topic Administrator using kafka-python AdminClient.")
    parser.add_argument("--bootstrap-servers", default="localhost:9092", help="Comma-separated list of Kafka bootstrap servers.")
    parser.add_argument("--operation", choices=["create", "describe", "alter-config", "delete", "list"], required=True,
                        help="Operation to perform: create, describe, alter-config, delete, list.")

    # Arguments for 'create' operation
    parser.add_argument("--create-topic", action='append', metavar="NAME:KEY=VALUE,KEY=VALUE...",
                        help="Specify topic name and configurations for creation. E.g., 'my-topic:partitions=3,replication_factor=2,retention.ms=60000'")

    # Arguments for 'describe', 'alter-config', 'delete' operations
    parser.add_argument("--topic-name", help="Specify a single topic name for describe, alter-config, or delete operations.")
    parser.add_argument("--topics", nargs='*', help="Specify multiple topic names for describe or delete operations.")

    # Arguments for 'alter-config' operation
    parser.add_argument("--alter-config", action='append', metavar="KEY=VALUE",
                        help="Configuration key-value pair to alter. E.g., 'retention.ms=3600000'")

    args = parser.parse_args()

    try:
        admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)
        print(f"Connected to Kafka cluster at {args.bootstrap_servers}")
    except NoBrokersAvailable:
        print(f"Error: No Kafka brokers available at {args.bootstrap_servers}")
        return
    except Exception as e:
        print(f"Error connecting to Kafka: {e}")
        return

    try:
        if args.operation == "create":
            if not args.create_topic:
                print("Error: --create-topic is required for 'create' operation.")
                return
            topics_to_create = {}
            for topic_arg in args.create_topic:
                if ':' not in topic_arg:
                    print(f"Warning: Invalid --create-topic format '{topic_arg}'. Expected 'NAME:KEY=VALUE...'. Skipping.")
                    continue
                topic_name, config_str = topic_arg.split(':', 1)
                configs = {}
                for item in config_str.split(','):
                    if '=' in item:
                        key, value = item.split('=', 1)
                        configs[key.strip()] = value.strip()
                topics_to_create[topic_name.strip()] = configs
            create_topics(admin_client, topics_to_create)

        elif args.operation == "describe":
            topics_to_describe = []
            if args.topic_name:
                topics_to_describe.append(args.topic_name)
            if args.topics:
                topics_to_describe.extend(args.topics)
            describe_topics(admin_client, topics_to_describe)

        elif args.operation == "alter-config":
            if not args.topic_name:
                print("Error: --topic-name is required for 'alter-config' operation.")
                return
            if not args.alter_config:
                print("Error: --alter-config KEY=VALUE is required for 'alter-config' operation.")
                return
            configs_to_alter = {}
            for config_item in args.alter_config:
                if '=' in config_item:
                    key, value = config_item.split('=', 1)
                    configs_to_alter[key.strip()] = value.strip()
                else:
                    print(f"Warning: Invalid --alter-config format '{config_item}'. Expected 'KEY=VALUE'. Skipping.")
            alter_topic_configs(admin_client, args.topic_name, configs_to_alter)

        elif args.operation == "delete":
            topics_to_delete = []
            if args.topic_name:
                topics_to_delete.append(args.topic_name)
            if args.topics:
                topics_to_delete.extend(args.topics)
            if not topics_to_delete:
                print("Error: --topic-name or --topics is required for 'delete' operation.")
                return
            delete_topics(admin_client, topics_to_delete)

        elif args.operation == "list":
            list_topics(admin_client)

    finally:
        admin_client.close()

if __name__ == "__main__":
    main()